private boolean isSpecialObject(Node node) {
  // Check for built-in objects or other special cases that should not be inlined
  String qualifiedName = node.getQualifiedName();
  return "arguments".equals(qualifiedName) || "this".equals(qualifiedName) || "window".equals(qualifiedName);
}

